225:+      containerStyle: {
226:+        type: "object",
227:+        description:
228:+          "CSS für den äußeren Block-Wrapper (camelCase). Beispiele: { paddingLeft: '2rem', marginBottom: '1rem', backgroundColor: 'hsl(var(--accent))' }.",
229:+      },
230:+      textStyle: {
231:+        type: "object",
232:+        description:
233:+          "CSS für den Text (camelCase). Beispiele: { fontSize: '1.25rem', fontWeight: '600', color: 'hsl(var(--primary))' }.",
234:+      },
235:+      itemStyle: {
236:+        type: "object",
237:+        description:
238:+          "CSS für Kind-Elemente wie <li>, <td> (camelCase). Beispiele: { paddingLeft: '1rem', marginBottom: '0.5rem' }.",
239:+      },
240:+      textTransform: {
241:+        type: "string",
242:+        enum: ["bold_prefix_before_colon", "render_markdown_strong"],
243:+      },
244:+      markdownTransform: {
245:+        type: "string",
246:+        enum: [
247:+          "promote_to_heading",
248:+          "normalize_list_structure",
249:+          "normalize_markdown_table",
250:+          "reshape_markdown_block",
251:+          "bold_prefix_before_colon",
252:+        ],
253:+      },
254:+      headingLevel: {
255:+        type: "number",
256:+        description: "Überschriften-Ebene 1-6.",
257:+      },
258:+      insertBefore: { type: "string", enum: ["hr", "spacer"] },
259:+      insertAfter: { type: "string", enum: ["hr", "spacer"] },
260:+    },
261:+    required: ["type"],
262:+  };
263:+}
264:+
265:+function buildTools() {
266:+  return [
267:+    {
268:+      type: "function",
269:+      name: "create_rule",
270:+      description:
271:+        "Erstellt eine neue Darstellungsregel für den ausgewählten Block.",
272:+      parameters: {
273:+        type: "object",
274:+        properties: {
275:+          selector: buildSelectorSchema(),
276:+          effect: buildEffectSchema(),
277:+          description: {
