301:+            description: "Aktualisierte Beschreibung (optional).",
302:+          },
303:+        },
304:+        required: ["ruleId", "effect"],
305:+        additionalProperties: false,
306:+      },
307:+      strict: false,
308:+    },
309:+    {
310:+      type: "function",
311:+      name: "delete_rule",
312:+      description: "Löscht eine bestehende Regel anhand ihrer ID.",
313:+      parameters: {
314:+        type: "object",
315:+        properties: {
316:+          ruleId: {
317:+            type: "string",
318:+            description: "ID der zu löschenden Regel.",
319:+          },
320:+        },
321:+        required: ["ruleId"],
322:+        additionalProperties: false,
323:+      },
324:+      strict: true,
325:+    },
326:+  ];
327:+}
328:+
329:+// ---------------------------------------------------------------------------
330:+// Context Builder
331:+// ---------------------------------------------------------------------------
332:+
333:+function blockToPlainText(block: Block) {
334:+  switch (block.type) {
335:+    case "paragraph":
336:+    case "heading":
337:+    case "quote":
338:+    case "code":
339:+      return block.text;
340:+    case "list":
341:+      return block.items.join("\n");
342:+    case "table":
343:+      return [
344:+        block.headers.join(" | "),
345:+        ...block.rows.map((row) => row.join(" | ")),
346:+      ].join("\n");
347:+  }
348:+}
349:+
350:+function summarizeSelection(
351:+  sessionDetail: AdjustmentSessionDetail,
352:+  job: ImportJob | undefined,
353:+) {
354:+  const { selection, targetFormat } = sessionDetail.session;
355:+
356:+  if (targetFormat === "markdown") {
357:+    const markdown = job?.artifacts?.markdown ?? "";
358:+    const lines = markdown.split("\n");
359:+    const lineStart = selection.lineStart ?? 1;
360:+    const lineEnd = selection.lineEnd ?? lineStart;
361:+
362:+    return {
363:+      currentExcerpt:
364:+        lines.slice(lineStart - 1, lineEnd).join("\n") ||
365:+        selection.selectedText,
366:+      description: `Markdown-Zeilen ${lineStart}-${lineEnd}`,
367:+      surrounding: {
368:+        next: lines[lineEnd] ?? null,
369:+        previous: lineStart > 1 ? (lines[lineStart - 2] ?? null) : null,
370:+      },
371:+    };
372:+  }
373:+
374:+  const message = job?.conversation?.messages.find(
375:+    (entry) => entry.id === selection.messageId,
376:+  );
377:+  const currentBlock = message?.blocks[selection.blockIndex];
378:+  const previousBlock =
379:+    selection.blockIndex > 0
380:+      ? message?.blocks[selection.blockIndex - 1]
381:+      : undefined;
382:+  const nextBlock = message?.blocks[selection.blockIndex + 1];
383:+
384:+  return {
385:+    currentExcerpt: currentBlock
386:+      ? blockToPlainText(currentBlock)
387:+      : selection.selectedText,
388:+    description: `${selection.messageRole} message ${selection.messageIndex + 1}, ${selection.blockType}`,
389:+    surrounding: {
390:+      next: nextBlock ? blockToPlainText(nextBlock) : null,
391:+      previous: previousBlock ? blockToPlainText(previousBlock) : null,
392:+    },
393:+  };
394:+}
395:+
396:+function buildSelectionContext(input: RunAgentTurnInput) {
397:+  const { activeRules, job, sessionDetail } = input;
398:+  const { selection, targetFormat } = sessionDetail.session;
399:+  const selectionContext = summarizeSelection(sessionDetail, job);
400:+  const lines: string[] = [];
401:+
402:+  lines.push("## Ausgewählter Block");
403:+  lines.push(`Format: ${targetFormat}`);
404:+  lines.push(
405:+    `Block: ${selection.blockType} (messageId: "${selection.messageId}", blockIndex: ${selection.blockIndex})`,

