214→      }
215→
216→      // Phase 1 — Transaction: reopen (if needed) + append user message + reload detail
217→      const latestDetail = withTransaction(() => {
218→        const freshDetail = getAdjustmentSessionDetail(input.sessionId);
219→
220→        if (!freshDetail) {
221→          throw new ORPCError("INTERNAL_SERVER_ERROR", {
222→            message: "Anpassungssession konnte nicht neu geladen werden.",
