225→
226→        if (freshDetail.session.status === "applied") {
227→          reopenAdjustmentSession(input.sessionId);
228→        }
229→
230→        appendAdjustmentMessage(input.sessionId, "user", input.content);
231→
232→        const reloaded = getAdjustmentSessionDetail(input.sessionId);
233→
234→        if (!reloaded) {
235→          throw new ORPCError("INTERNAL_SERVER_ERROR", {
236→            message: "Anpassungssession konnte nicht neu geladen werden.",
237→          });
238→        }
239→
240→        return reloaded;
241→      });
242→
243→      const activeRules = listFormatRules(
244→        detail.session.importId,
245→        detail.session.targetFormat,
246→      ).filter((rule: { status: string }) => rule.status === "active");
247→
248→      // Phase 2 — no wrapper: async AI call
249→      try {
250→        const job = getImportJob(detail.session.importId);
251→        const result = await runAgentTurn({
252→          sessionDetail: latestDetail,
253→          activeRules,
254→          job,
255→          callbacks: {
256→            onCreateRule: async ({ selector, effect, description }) => {
257→              const rule = createFormatRuleDirect({
258→                importId: latestDetail.session.importId,
259→                targetFormat: latestDetail.session.targetFormat,
260→                selector,
261→                effect: {
262→                  type: "custom_style" as const,
263→                  ...effect,
264→                  description,
265→                },
266→                instruction: description,
267→                sourceSessionId: input.sessionId,
268→              });
269→              return { ruleId: rule.id };
270→            },
271→            onUpdateRule: async ({ ruleId, effect, description }) => {
272→              updateFormatRuleEffect(
273→                ruleId,
274→                { type: "custom_style" as const, ...effect, description },
275→                description,
276→              );
277→            },
278→            onDeleteRule: async (ruleId) => {
279→              disableFormatRule(ruleId, latestDetail.session.importId);
280→            },
281→          },
282→        });
283→
284→        // Phase 3 — persist assistant message + events
285→        withTransaction(() => {
286→          appendAdjustmentMessage(
287→            input.sessionId,
288→            "assistant",
289→            result.assistantMessage,
290→          );
291→
292→          for (const action of result.actions) {
293→            recordAdjustmentEvent({
294→              importId: latestDetail.session.importId,
295→              ruleId: action.ruleId,
296→              sessionId: input.sessionId,
297→              targetFormat: latestDetail.session.targetFormat,
298→              type:
299→                action.type === "deleted" ? "rule_disabled" : "rule_applied",
300→            });
301→          }
302→
303→          if (result.actions.length > 0) {
