306→            recordAdjustmentEvent({
307→              importId: latestDetail.session.importId,
308→              sessionId: input.sessionId,
309→              targetFormat: latestDetail.session.targetFormat,
310→              type: "clarification_requested",
311→            });
312→          }
313→        });
314→      } catch (error) {
315→        if (error instanceof AgentUnavailableError) {
316→          throw new ORPCError("SERVICE_UNAVAILABLE", {
317→            message: error.message,
318→          });
319→        }
320→        if (error instanceof DOMException && error.name === "TimeoutError") {
321→          throw new ORPCError("GATEWAY_TIMEOUT", {
322→            message: "Die KI hat zu lange gebraucht. Bitte versuche es erneut.",
323→          });
324→        }
325→        throw new ORPCError("BAD_REQUEST", {
326→          message:
327→            error instanceof Error
328→              ? error.message
329→              : "Die Live-KI-Nachricht konnte nicht verarbeitet werden.",
330→        });
331→      }
332→
333→      const nextDetail = getAdjustmentSessionDetail(input.sessionId);
334→
335→      if (!nextDetail) {
336→        throw new ORPCError("INTERNAL_SERVER_ERROR", {
337→          message: "Anpassungssession konnte nicht neu geladen werden.",
338→        });
339→      }
340→
341→      return nextDetail;
342→    }),
