458→          message:
459→            error instanceof Error
460→              ? error.message
461→              : "Round konnte nicht gelöscht werden.",
462→        });
463→      }
464→    }),
465→
466→    restore: os.deletions.restore.handler(({ input }) => {
467→      try {
468→        const restored = withTransaction(() => {
469→          const result = restoreMessage(input.importId, input.messageId);
470→          if (result) {
471→            recordAdjustmentEvent({
472→              importId: input.importId,
473→              targetFormat: "reader",
474→              type: "message_restored",
475→              payload: { messageId: input.messageId },
476→            });
477→          }
478→          return result;
479→        });
480→        return { restored };
481→      } catch (error) {
482→        throw new ORPCError("BAD_REQUEST", {
483→          message:
484→            error instanceof Error
485→              ? error.message
486→              : "Message konnte nicht wiederhergestellt werden.",
487→        });
488→      }
489→    }),
490→  },
491→
492→  health: {
493→    check: os.health.check.handler(() => {
