  4→import { ErrorBoundary } from "@/components/error-boundary";
  5→import { AdjustmentModeGuide } from "@/components/format-workspace/adjustment-mode-guide";
  6→import { AdjustmentPopover } from "@/components/format-workspace/adjustment-popover";
  7→import { ArtifactView } from "@/components/format-workspace/artifact-view";
  8→import { CompletedToolbar } from "@/components/format-workspace/completed-toolbar";
  9→import { DeleteMessageDialog } from "@/components/format-workspace/delete-message-dialog";
 10→import {
 11→  formatMarkdownLinesLabel,
 12→  formatMessageBlockLabel,
 13→  getImportStageLabel,
 14→  miscLabels,
 15→} from "@/components/format-workspace/labels";
 16→import { LoadingStateBlock } from "@/components/format-workspace/loading-state-block";
 17→import { MarkdownView } from "@/components/format-workspace/markdown-view";
 18→import { ReaderView } from "@/components/format-workspace/reader-view";
 19→import {
 20→  applyMarkdownRules,
 21→  buildReaderEffectsMap,
 22→} from "@/components/format-workspace/rule-engine";
 23→import { StatusHeader } from "@/components/format-workspace/status-header";
 24→import {
 25→  type AdjustmentSelection,
 26→  adjustableViews,
 27→  type ViewMode,
 28→} from "@/components/format-workspace/types";
 29→import { UndoToast } from "@/components/format-workspace/undo-toast";
 30→import { useAdjustmentPopover } from "@/components/format-workspace/use-adjustment-popover";
 31→import { useAdjustmentSession } from "@/components/format-workspace/use-adjustment-session";
 32→import { useDeletionToast } from "@/components/format-workspace/use-deletion-toast";
 33→import { useFormatRules } from "@/components/format-workspace/use-format-rules";
 34→import { useMessageDeletion } from "@/components/format-workspace/use-message-deletion";
 35→
 36→type ActiveStage = {
 37→  detail: string;
 38→  label: string;
 39→} | null;
 40→
 41→type FormatWorkspaceProps = {
 42→  activeStage: ActiveStage;
 43→  elapsedTime: string;
 44→  job: ImportJob;
 45→  view: ViewMode;
 46→  onViewChange: (view: ViewMode) => void;
 47→};
 48→
 49→function _describeSelectionLabel(selection: AdjustmentSelection) {
 50→  if (selection.lineStart !== undefined && selection.lineEnd !== undefined) {
 51→    return formatMarkdownLinesLabel(selection.lineStart, selection.lineEnd);
 52→  }
 53→
 54→  return formatMessageBlockLabel(
 55→    selection.messageRole,
 56→    selection.messageIndex + 1,
 57→    selection.blockType,
 58→  );
 59→}
 60→
 61→function renderArtifact(view: Exclude<ViewMode, "reader">, job: ImportJob) {
 62→  if (!job.artifacts) {
 63→    return "Artefakt ist noch nicht verfügbar.";
 64→  }
 65→
 66→  switch (view) {
 67→    case "markdown":
 68→      return job.artifacts.markdown;
 69→    case "handover":
 70→      return job.artifacts.handover;
 71→    case "json":
 72→      return job.artifacts.json;
 73→  }
 74→}
 75→
 76→export function FormatWorkspace({
 77→  activeStage,
 78→  elapsedTime,
 79→  job,
 80→  view,
 81→  onViewChange,
 82→}: FormatWorkspaceProps) {
 83→  const isAdjustableView = adjustableViews.has(view);
 84→
 85→  const session = useAdjustmentSession(view, job.id);
 86→  const rules = useFormatRules(view, job.id);
 87→  const deletion = useMessageDeletion(job.id);
 88→  const deletionToast = useDeletionToast();
 89→  const [deleteDialog, setDeleteDialog] = useState<{
 90→    messageId: string;
 91→    isRound: boolean;
 92→    preview: string;
 93→  } | null>(null);
 94→  const popover = useAdjustmentPopover();
 95→
 96→  const handleDeleteMessage = useCallback(
 97→    (messageId: string) => {
 98→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
 99→      const preview =
100→        msg?.blocks
101→          .map((b) => ("text" in b ? b.text : b.type))
102→          .join(" ")
103→          .slice(0, 200) ?? messageId;
104→      setDeleteDialog({ messageId, isRound: false, preview });
105→    },
106→    [job.conversation?.messages],
107→  );
108→
109→  const handleDeleteRound = useCallback(
110→    (messageId: string) => {
111→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
112→      const preview =
113→        msg?.blocks
114→          .map((b) => ("text" in b ? b.text : b.type))
115→          .join(" ")
116→          .slice(0, 200) ?? messageId;
117→      setDeleteDialog({ messageId, isRound: true, preview });
118→    },
119→    [job.conversation?.messages],
120→  );
121→
122→  const handleConfirmDelete = useCallback(
123→    async (reason?: string) => {
124→      if (!deleteDialog) return;
125→      const { messageId, isRound } = deleteDialog;
126→      setDeleteDialog(null);
127→      if (isRound) {
128→        const result = await deletion.deleteRound(messageId, reason);
129→        deletionToast.showDeletedToast(messageId, true, result.length);
130→      } else {
131→        await deletion.deleteMessage(messageId, reason);
132→        deletionToast.showDeletedToast(messageId, false);
133→      }
134→    },
135→    [deleteDialog, deletion, deletionToast],
136→  );
137→
138→  const handleUndoDelete = useCallback(async () => {
139→    if (!deletionToast.toast) return;
140→    await deletion.restoreMessage(deletionToast.toast.messageId);
141→    deletionToast.dismissToast();
142→  }, [deletion, deletionToast]);
143→
144→  const mergedRef = useCallback(
145→    (node: HTMLElement | null) => {
146→      (
147→        session.sectionRef as React.MutableRefObject<HTMLElement | null>
148→      ).current = node;
149→      (
150→        popover.containerRef as React.MutableRefObject<HTMLElement | null>
151→      ).current = node;
152→    },
153→    [session.sectionRef, popover.containerRef],
154→  );
155→
156→  const artifact = view === "reader" ? "" : renderArtifact(view, job);
157→  // Design-Entscheidung: Downloads erfolgen aus `displayedMarkdown`, das
158→  // `applyMarkdownRules` inklusive format_profile-Rules enthält. Der Server-
159→  // Endpoint `imports.exportArtifact` liefert hingegen rohe Artefakte ohne Rules.
160→  const displayedMarkdown = useMemo(() => {
161→    if (view !== "markdown") return artifact;
162→    try {
163→      return applyMarkdownRules(artifact, rules.activeRules);
164→    } catch {
165→      return artifact;
166→    }
167→  }, [artifact, rules.activeRules, view]);
168→
169→  const readerEffectsMap = useMemo(
170→    () =>
171→      view === "reader" && job.conversation
172→        ? buildReaderEffectsMap(rules.activeRules, job.conversation)
173→        : new Map(),
174→    [rules.activeRules, job.conversation, view],
175→  );
176→
177→  const handleDownloadMarkdown = useMemo(() => {
178→    if (view !== "markdown") return undefined;
179→    return () => {
180→      const blob = new Blob([displayedMarkdown], { type: "text/markdown" });
181→      const url = URL.createObjectURL(blob);
182→      const a = document.createElement("a");
183→      a.href = url;
184→      a.download = `export-${job.id}.md`;
185→      document.body.appendChild(a);
186→      a.click();
187→      document.body.removeChild(a);
188→      setTimeout(() => URL.revokeObjectURL(url), 100);
189→    };
190→  }, [view, displayedMarkdown, job.id]);
191→  const showPopover =
192→    session.adjustModeEnabled &&
193→    Boolean(session.activeSelection) &&
194→    Boolean(session.activeAnchor);
195→
196→  const popoverCallbacksRef = useRef({
197→    handleDiscardSession: session.handleDiscardSession,
198→    activeSessionDetail: session.activeSessionDetail,
199→    handleRejectLastChange: rules.handleRejectLastChange,
200→    setReplyVisible: session.setReplyVisible,
201→  });
202→  popoverCallbacksRef.current = {
203→    handleDiscardSession: session.handleDiscardSession,
204→    activeSessionDetail: session.activeSessionDetail,
205→    handleRejectLastChange: rules.handleRejectLastChange,
206→    setReplyVisible: session.setReplyVisible,
207→  };
208→
209→  const handlePopoverClose = useCallback(() => {
210→    popoverCallbacksRef.current.handleDiscardSession();
211→  }, []);
212→
213→  const handleRejectLastChange = useCallback(() => {
214→    const {
215→      activeSessionDetail,
216→      handleRejectLastChange: reject,
217→      setReplyVisible,
218→    } = popoverCallbacksRef.current;
219→    if (activeSessionDetail) {
220→      void reject(activeSessionDetail).then((success) => {
221→        if (success) setReplyVisible(false);
222→      });
223→    }
224→  }, []);
225→
226→  const sessionError =
227→    session.activeSessionError ?? rules.disableError ?? rules.promoteError;
228→
229→  const viewErrorFallback = (_error: Error, reset: () => void) => (
230→    <div className="flex flex-col items-center justify-center gap-4 p-8 text-center">
231→      <p className="text-red-700">{miscLabels.viewLoadError}</p>
232→      <button
233→        className="rounded-lg border border-border px-4 py-2 text-sm hover:bg-foreground/5"
234→        type="button"
235→        onClick={reset}
236→      >
237→        {miscLabels.retryButton}
238→      </button>
239→    </div>
240→  );
241→
242→  return (
243→    <section
244→      ref={mergedRef}
245→      className="relative space-y-4 rounded-[1.9rem] border border-border/80 bg-background/70 p-4 sm:p-5"
246→    >
247→      <StatusHeader
248→        activeStage={activeStage}
249→        elapsedTime={elapsedTime}
250→        job={job}
251→      />
252→
253→      {job.warnings.length > 0 ? (
254→        <div className="rounded-2xl border border-amber-300/40 bg-amber-100/60 px-4 py-3 text-sm text-amber-950">
255→          {job.warnings[0]}
256→        </div>
257→      ) : null}
258→
259→      {job.status === "failed" ? (
260→        <div className="rounded-2xl border border-red-300/40 bg-red-100/70 p-4 text-red-900">
261→          <p className="font-medium">{miscLabels.importFailed}</p>
262→          {job.errorStage && job.errorStage !== "done" && (
263→            <p className="text-sm mt-1">
264→              {miscLabels.errorInPhase(getImportStageLabel(job.errorStage))}
265→            </p>
266→          )}
267→          {job.error && <p className="text-sm mt-1">{job.error}</p>}
268→        </div>
269→      ) : job.status === "queued" || job.status === "running" ? (
270→        <LoadingStateBlock stageDetail={activeStage?.detail} />
271→      ) : (
272→        <div className="space-y-4">
273→          <CompletedToolbar
274→            adjustModeEnabled={session.adjustModeEnabled}
275→            isAdjustableView={isAdjustableView}
276→            rules={rules}
277→            view={view}
278→            onDownloadMarkdown={handleDownloadMarkdown}
279→            onToggleAdjustMode={session.toggleAdjustMode}
280→            onViewChange={onViewChange}
281→            deletionsCount={deletion.deletionsCount}
282→            showDeleted={deletion.showDeleted}
283→            onToggleShowDeleted={() =>
284→              deletion.setShowDeleted(!deletion.showDeleted)
285→            }
286→          />
287→
288→          {sessionError && !session.adjustModeEnabled ? (
289→            <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
290→              {sessionError}
291→            </div>
292→          ) : null}
293→
294→          {view === "reader" ? (
295→            <ErrorBoundary fallback={viewErrorFallback}>
296→              <ReaderView
297→                activeRules={rules.activeRules}
298→                conversation={job.conversation}
299→                adjustModeEnabled={session.adjustModeEnabled}
300→                effectsMap={readerEffectsMap}
301→                highlightedRuleId={rules.hoveredRuleId}
302→                selectedBlock={
303→                  view === "reader" ? session.activeSelection : null
304→                }
305→                onSelectBlock={session.handleSelectionChange}
306→                deletedMessageIds={deletion.deletedMessageIds}
307→                showDeleted={deletion.showDeleted}
308→                onDeleteMessage={handleDeleteMessage}
309→                onDeleteRound={handleDeleteRound}
310→                onRestoreMessage={deletion.restoreMessage}
311→              />
312→            </ErrorBoundary>
313→          ) : view === "markdown" ? (
314→            <ErrorBoundary fallback={viewErrorFallback}>
315→              <MarkdownView
316→                activeRules={rules.activeRules}
317→                content={displayedMarkdown}
318→                adjustModeEnabled={session.adjustModeEnabled}
319→                highlightedRuleId={rules.hoveredRuleId}
320→                selectedRange={session.activeSelection}
321→                onSelectLines={session.handleSelectionChange}
322→              />
323→            </ErrorBoundary>
324→          ) : (
325→            <ErrorBoundary fallback={viewErrorFallback}>
326→              <ArtifactView content={artifact} />
327→            </ErrorBoundary>
328→          )}
329→
330→          {session.showGuide ? (
331→            <AdjustmentModeGuide
332→              view={view}
333→              onDismiss={() => session.setGuideDismissed(true)}
334→            />
335→          ) : null}
336→
337→          <ErrorBoundary
338→            fallback={
339→              <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
340→                {miscLabels.adjustmentLoadError}
341→              </div>
342→            }
343→          >
344→            <AdjustmentPopover
345→              anchor={session.activeAnchor ?? null}
346→              containerRef={session.sectionRef}
347→              draftMessage={session.activeDraftMessage}
348→              error={session.activeSessionError}
349→              isLoading={session.activeSessionLoading || session.isDiscarding}
350→              isSubmitting={session.isSubmitting}
351→              open={
352→                showPopover &&
353→                Boolean(session.activeSelection) &&
354→                Boolean(session.activeAnchor)
355→              }
356→              sessionDetail={session.activeSessionDetail}
357→              showReply={session.replyVisible}
358→              view={view}
359→              onClose={handlePopoverClose}
360→              onDraftMessageChange={session.handleDraftMessageChange}
361→              onRejectLastChange={handleRejectLastChange}
362→              onSubmitMessage={session.handleSubmitMessage}
363→            />
364→          </ErrorBoundary>
365→        </div>
366→      )}
367→
368→      {deleteDialog && (
369→        <DeleteMessageDialog
370→          messagePreview={deleteDialog.preview}
371→          isRound={deleteDialog.isRound}
372→          onConfirm={(reason) => {
373→            void handleConfirmDelete(reason);
374→          }}
375→          onCancel={() => setDeleteDialog(null)}
376→        />
377→      )}
378→
379→      {deletionToast.toast && (
380→        <UndoToast
381→          message={deletionToast.toast.message}
382→          onUndo={() => {
383→            void handleUndoDelete();
384→          }}
385→          onDismiss={deletionToast.dismissToast}
386→        />
387→      )}
388→    </section>
389→  );
390→}
