+            input.importId,
+            input.messageId,
+            input.reason,
+          );
+          recordAdjustmentEvent({
+            importId: input.importId,
+            targetFormat: "reader",
+            type: "round_deleted",
+            payload: { messageId: input.messageId, count: result.length },
+          });
+          return result;
+        });
+        return deletions;
+      } catch (error) {
+        throw new ORPCError("BAD_REQUEST", {
+          message:
+            error instanceof Error
+              ? error.message
+              : "Round konnte nicht gelöscht werden.",
+        });
