+          message:
+            error instanceof Error
+              ? error.message
+              : "Message konnte nicht wiederhergestellt werden.",
+        });
+      }
+    }),
+  },
+
+  health: {
+    check: os.health.check.handler(() => {
+      return {
+        ok: true as const,
+        service: "chat-exporter-api",
+        databasePath,
+      };
+    }),
+  },
+});

