269→export function ReaderView({
270→  activeRules,
271→  adjustModeEnabled,
272→  conversation,
273→  deletedMessageIds,
274→  effectsMap,
275→  highlightedRuleId,
276→  onDeleteMessage,
277→  onDeleteRound,
278→  onRestoreMessage,
279→  onSelectBlock,
280→  selectedBlock,
281→  showDeleted,
282→}: ReaderViewProps) {
283→  const visibleMessages = useMemo(() => {
284→    if (!conversation?.messages) return [];
285→    if (!deletedMessageIds?.size) return conversation.messages;
286→    if (showDeleted) return conversation.messages;
287→    return conversation.messages.filter((m) => !deletedMessageIds.has(m.id));
288→  }, [conversation?.messages, deletedMessageIds, showDeleted]);
289→
290→  const highlightedBlocks = useMemo(() => {
291→    if (!highlightedRuleId || !conversation) {
292→      return new Set<string>();
293→    }
294→
295→    const rule = activeRules.find(
296→      (r) => r.id === highlightedRuleId && r.status === "active",
297→    );
298→
299→    if (!rule) {
300→      return new Set<string>();
301→    }
302→
303→    const matches = getBlocksMatchingRule(rule, conversation);
304→    return new Set(matches.map((m) => `${m.messageId}:${m.blockIndex}`));
305→  }, [highlightedRuleId, activeRules, conversation]);
306→
307→  if (!conversation?.messages.length) {
308→    return (
309→      <div className="rounded-2xl border border-border/80 bg-card/75 px-4 py-5 text-sm text-muted-foreground">
310→        Für diesen Import ist noch kein Transkriptinhalt verfügbar.
311→      </div>
312→    );
313→  }
314→
315→  return (
316→    <div className="space-y-3">
317→      {visibleMessages.map((message, index) => (
318→        <ReaderMessage
319→          key={message.id}
320→          adjustModeEnabled={adjustModeEnabled}
321→          effectsMap={effectsMap}
322→          highlightedBlocks={highlightedBlocks}
323→          message={message}
324→          messageIndex={index}
325→          onSelectBlock={onSelectBlock}
326→          selectedBlock={selectedBlock}
327→          isDeleted={deletedMessageIds?.has(message.id)}
328→          onDeleteMessage={
329→            onDeleteMessage ? () => onDeleteMessage(message.id) : undefined
330→          }
331→          onDeleteRound={
332→            onDeleteRound ? () => onDeleteRound(message.id) : undefined
333→          }
334→          onRestore={
335→            onRestoreMessage
336→              ? () => {
337→                  void onRestoreMessage(message.id);
338→                }
339→              : undefined
340→          }
341→        />
342→      ))}
343→    </div>
344→  );
345→}
