 26→export function resolveReaderBlockEffects(
 27→  rules: FormatRule[],
 28→  messageId: string,
 29→  blockIndex: number,
 30→  blockType: Block["type"],
 31→  blockText: string,
 32→) {
 33→  return rules
 34→    .filter(
 35→      (rule) =>
 36→        rule.status === "active" &&
 37→        matchesReaderRule(rule, messageId, blockIndex, blockType, blockText),
 38→    )
 39→    .map((rule) => rule.compiledRule)
 40→    .filter((effect): effect is RuleEffect => effect !== undefined)
 41→    .map(normalizeLegacyEffect);
 42→}
 43→
 44→export function buildReaderEffectsMap(
 45→  rules: FormatRule[],
 46→  conversation: Conversation,
 47→): Map<string, RuleEffect[]> {
 48→  const activeRules = rules.filter((r) => r.status === "active");
 49→  const effectsMap = new Map<string, RuleEffect[]>();
 50→
 51→  for (const message of conversation.messages) {
 52→    for (
 53→      let blockIndex = 0;
 54→      blockIndex < message.blocks.length;
 55→      blockIndex += 1
 56→    ) {
 57→      const block = message.blocks[blockIndex];
 58→
 59→      if (!block) {
 60→        continue;
 61→      }
 62→
 63→      const effects = activeRules
 64→        .filter((rule) =>
 65→          matchesReaderRule(
 66→            rule,
 67→            message.id,
 68→            blockIndex,
 69→            block.type,
 70→            blockToPlainText(block),
 71→          ),
 72→        )
 73→        .map((rule) => rule.compiledRule)
 74→        .filter((effect): effect is RuleEffect => effect !== undefined)
 75→        .map(normalizeLegacyEffect);
 76→
 77→      if (effects.length > 0) {
 78→        effectsMap.set(`${message.id}:${blockIndex}`, effects);
 79→      }
 80→    }
 81→  }
 82→
 83→  return effectsMap;
 84→}
