 86→export function applyMarkdownRules(content: string, rules: FormatRule[]) {
 87→  const lines = content.split("\n");
 88→  const nextLines = [...lines];
 89→
 90→  for (const rule of rules) {
 91→    if (rule.status !== "active") {
 92→      continue;
 93→    }
 94→
 95→    const parsedSelector = ruleSelectorSchema.safeParse(rule.selector);
 96→    const parsedEffect = ruleEffectSchema.safeParse(rule.compiledRule);
 97→
 98→    if (!parsedSelector.success || !parsedEffect.success) {
 99→      continue;
100→    }
101→
102→    const selector = parsedSelector.data;
103→    const effect = normalizeLegacyEffect(parsedEffect.data);
104→
105→    const strategy = "strategy" in selector ? selector.strategy : undefined;
106→
107→    // All effects are now custom_style after normalization
108→    {
109→      const transform = effect.markdownTransform;
110→      if (!transform) continue;
111→
112→      if (
113→        strategy === "prefix_before_colon" &&
114→        transform === "bold_prefix_before_colon"
115→      ) {
116→        for (let index = 0; index < nextLines.length; index += 1) {
117→          const line = nextLines[index] ?? "";
118→          nextLines[index] = line.replace(/^([^:\n]{1,120}:)(?!\*)/, "**$1**");
119→        }
120→        continue;
121→      }
122→
123→      if (
124→        strategy === "markdown_table" &&
125→        transform === "normalize_markdown_table"
126→      ) {
127→        for (let index = 0; index < nextLines.length; index += 1) {
128→          const line = nextLines[index] ?? "";
129→          if (!line.includes("|")) continue;
130→          nextLines[index] = line
131→            .split("|")
132→            .map((cell) => cell.trim())
133→            .join(" | ")
134→            .trim();
135→        }
136→        continue;
137→      }
138→
139→      const lineStart = "lineStart" in selector ? selector.lineStart : null;
140→      const lineEnd = "lineEnd" in selector ? selector.lineEnd : lineStart;
141→      if (!lineStart || !lineEnd) continue;
142→      const startIndex = Math.max(0, lineStart - 1);
143→      const endIndex = Math.min(nextLines.length - 1, lineEnd - 1);
144→
145→      switch (transform) {
146→        case "promote_to_heading":
147→          nextLines[startIndex] =
148→            `## ${nextLines[startIndex]?.replace(/^#+\s*/, "") ?? ""}`.trimEnd();
149→          break;
150→        case "bold_prefix_before_colon":
151→          for (let index = startIndex; index <= endIndex; index += 1) {
152→            const line = nextLines[index] ?? "";
153→            nextLines[index] = line.replace(
154→              /^([^:\n]{1,120}:)(?!\*)/,
155→              "**$1**",
156→            );
157→          }
158→          break;
159→        case "normalize_list_structure":
160→          for (let index = startIndex; index <= endIndex; index += 1) {
161→            const line = nextLines[index] ?? "";
162→            const trimmedLine = line.trim();
163→            if (!trimmedLine) continue;
164→            nextLines[index] = /^[-*]\s/.test(trimmedLine)
165→              ? trimmedLine
166→              : `- ${trimmedLine}`;
167→          }
168→          break;
169→        case "normalize_markdown_table":
170→          for (let index = startIndex; index <= endIndex; index += 1) {
171→            const line = nextLines[index] ?? "";
172→            nextLines[index] = line
173→              .split("|")
174→              .map((cell) => cell.trim())
175→              .join(" | ")
176→              .trim();
177→          }
178→          break;
179→        case "reshape_markdown_block":
180→          for (let index = startIndex; index <= endIndex; index += 1) {
181→            nextLines[index] = (nextLines[index] ?? "").trimEnd();
182→          }
183→          break;
184→      }
185→    }
186→  }
187→
188→  return nextLines.join("\n");
189→}
