525→export function getAdjustmentMetrics(
526→  importId: string,
527→  targetFormat: AdjustmentTargetFormat,
528→): AdjustmentMetrics {
529→  const row = db.get<{
530→    sessions_created: number | null;
531→    clarifications: number | null;
532→    previews_generated: number | null;
533→    preview_failures: number | null;
534→    rules_applied: number | null;
535→    rules_disabled: number | null;
536→    sessions_discarded: number | null;
537→    updated_at: string | null;
538→  }>(sql`
539→    SELECT
540→      SUM(CASE WHEN event_type = 'session_created' THEN 1 ELSE 0 END) AS sessions_created,
541→      SUM(CASE WHEN event_type = 'clarification_requested' THEN 1 ELSE 0 END) AS clarifications,
542→      SUM(CASE WHEN event_type = 'preview_generated' THEN 1 ELSE 0 END) AS previews_generated,
543→      SUM(CASE WHEN event_type = 'preview_failed' THEN 1 ELSE 0 END) AS preview_failures,
544→      SUM(CASE WHEN event_type = 'rule_applied' THEN 1 ELSE 0 END) AS rules_applied,
545→      SUM(CASE WHEN event_type = 'rule_disabled' THEN 1 ELSE 0 END) AS rules_disabled,
546→      SUM(CASE WHEN event_type = 'session_discarded' THEN 1 ELSE 0 END) AS sessions_discarded,
547→      MAX(created_at) AS updated_at
548→    FROM ${adjustmentEvents}
549→    WHERE ${adjustmentEvents.importId} = ${importId}
550→      AND ${adjustmentEvents.targetFormat} = ${targetFormat}
