 97→function describeSelectorStrategy(selector: unknown): string {
 98→  const s =
 99→    selector && typeof selector === "object"
100→      ? (selector as Record<string, unknown>)
101→      : null;
102→  if (!s) return "Unbekannter Selektor";
103→
104→  const strategy = s.strategy as string | undefined;
105→  const blockType =
106→    typeof s.blockType === "string" ? getBlockTypeLabel(s.blockType) : null;
107→
108→  switch (strategy) {
109→    case "exact":
110→      return blockType
111→        ? `Exakter Block: ${blockType} #${(s.blockIndex as number) + 1}`
112→        : "Exakter Block";
113→    case "block_type":
114→      return blockType
115→        ? `Alle Blöcke vom Typ: ${blockType}`
116→        : "Alle Blöcke eines Typs";
117→    case "prefix_before_colon":
118→      return blockType
119→        ? `Präfix vor Doppelpunkt in: ${blockType}`
120→        : "Präfix vor Doppelpunkt";
121→    case "markdown_table":
122→      return "Alle Markdown-Tabellen";
123→    default:
124→      return `Strategie: ${strategy ?? "unbekannt"}`;
125→  }
126→}
