687→  }
688→
689→  if (existingRule.status !== "active") {
690→    throw new Error("Nur aktive Regeln können deaktiviert werden.");
691→  }
692→
693→  const resolvedImportId = existingRule.importId ?? importId;
694→
695→  if (!resolvedImportId) {
696→    throw new Error(
697→      "Für Profil-Regeln muss eine gültige importId angegeben werden.",
698→    );
699→  }
700→
701→  db.transaction((tx) => {
702→    const timestamp = now();
703→
704→    tx.update(formatRules)
705→      .set({
706→        status: "disabled",
707→        updatedAt: timestamp,
708→      })
709→      .where(eq(formatRules.id, ruleId))
710→      .run();
711→
712→    recordAdjustmentEvent(
713→      {
714→        importId: resolvedImportId,
715→        ruleId: existingRule.id,
716→        sessionId: existingRule.sourceSessionId,
717→        targetFormat: existingRule.targetFormat,
718→        type: "rule_disabled",
719→      },
720→      tx,
721→    );
722→  });
723→
724→  const nextRule = getFormatRule(ruleId);
725→
726→  if (!nextRule) {
727→    throw new Error("Formatregel konnte nicht neu geladen werden.");
728→  }
729→
730→  return nextRule;
731→}
