  1→import type {
  2→  Block,
  3→  Conversation,
  4→  FormatRule,
  5→  RuleEffect,
  6→} from "@chat-exporter/shared";
  7→import {
  8→  normalizeLegacyEffect,
  9→  ruleEffectSchema,
 10→  ruleSelectorSchema,
 11→} from "@chat-exporter/shared";
 12→
 13→import { blockToPlainText } from "./reader-block-render";
 14→import { matchesReaderRule } from "./rule-matching";
 15→
 16→// Re-exports for backward compatibility
 17→export {
 18→  blockToPlainText,
 19→  collectInserts,
 20→  getReaderBlockClassName,
 21→  getReaderBlockStyle,
 22→  renderReaderBlock,
 23→} from "./reader-block-render";
