269→export function ReaderView({
270→  activeRules,
271→  adjustModeEnabled,
272→  conversation,
273→  deletedMessageIds,
274→  effectsMap,
275→  highlightedRuleId,
276→  onDeleteMessage,
277→  onDeleteRound,
278→  onRestoreMessage,
279→  onSelectBlock,
280→  selectedBlock,
281→  showDeleted,
282→}: ReaderViewProps) {
283→  const visibleMessages = useMemo(() => {
