 11→function mentions(input: string, pattern: RegExp) {
 12→  return pattern.test(input);
 13→}
 14→
 15→function wantsBroadRule(input: string) {
 16→  return mentions(
 17→    input,
 18→    /\b(always|whenever|every|all similar|same kind|all|immer|ueberall|überall|alle ähnlichen|aehnlichen|ähnlichen|ähnliche|aehnliche|ähnliche|generell|standardmäßig|standardmaessig|jeder|jede|jedes)\b/i,
 19→  );
