 22→function hasLabelStylePrefix(text: string) {
 23→  const firstLine = text.trim().split("\n")[0] ?? "";
 24→  const match = firstLine.match(/^([^:\n]{1,48}:)(\s|$)/);
 25→  if (!match) return false;
 26→  const matchedPrefix = match[1];
 27→  if (!matchedPrefix) return false;
 28→  const prefix = matchedPrefix.slice(0, -1).trim();
 29→  if (!prefix || /[.!?]/.test(prefix)) return false;
 30→  const words = prefix.split(/\s+/).filter(Boolean);
 31→  return words.length > 0 && words.length <= 6;
 32→}
