export function findReusableAdjustmentSession(
  input: CreateAdjustmentSessionInput,
) {
  return listAdjustmentSessions(input.importId, input.targetFormat).find(
    (session) =>
      session.status === "open" &&
      selectionsMatch(session.selection, input.selection),
  );
}

