116→  effect: { type: "custom_style", containerStyle: { marginBottom: "1.5rem" } }
117→  description: "Mehr Abstand unter dem Absatz"
118→
119→Nutzer wählt einen Absatz und sagt: "Mach den Text fett"
120→→ create_rule mit:
121→  selector: { strategy: "exact", messageId: "<aus Kontext>", blockIndex: <aus Kontext>, blockType: "paragraph" }
122→  effect: { type: "custom_style", textStyle: { fontWeight: "700" } }
123→  description: "Text fett dargestellt"
124→
125→Nutzer sagt: "Alle Listen sollen mehr Abstand haben"
126→→ create_rule mit:
127→  selector: { strategy: "block_type", blockType: "list" }
128→  effect: { type: "custom_style", containerStyle: { marginBottom: "1rem", marginTop: "1rem" } }
129→  description: "Mehr Abstand um alle Listen"`;
130→
131→  const markdownExamples = `## Beispiele
132→
133→Nutzer wählt eine Textzeile und sagt: "Das soll eine Überschrift werden"
134→→ create_rule mit:
135→  selector: { strategy: "exact", messageId: "<aus Kontext>", blockIndex: <aus Kontext>, blockType: "paragraph" }
136→  effect: { type: "custom_style", markdownTransform: "promote_to_heading" }
137→  description: "Zeile zur Überschrift gemacht"
