  1→import type { Browser, BrowserContext } from "playwright";
  2→import { chromium } from "playwright";
  3→
  4→import {
  5→  BROWSER_IDLE_SHUTDOWN_MS,
  6→  MAX_CONCURRENT_BROWSER_CONTEXTS,
  7→} from "./constants.js";
  8→
  9→export const MAX_CONTEXTS_PER_BROWSER = 50;
 10→
 11→type QueueEntry = {
 12→  resolve: (ctx: BrowserContext) => void;
 13→  reject: (err: Error) => void;
 14→};
 15→
 16→let browser: Browser | null = null;
 17→let activeContextCount = 0;
 18→let totalContextCount = 0;
 19→let idleTimer: ReturnType<typeof setTimeout> | null = null;
 20→const queue: QueueEntry[] = [];
 21→
 22→function clearIdleTimer() {
 23→  if (idleTimer !== null) {
 24→    clearTimeout(idleTimer);
 25→    idleTimer = null;
 26→  }
 27→}
 28→
 29→function scheduleIdleShutdown() {
 30→  clearIdleTimer();
 31→  idleTimer = setTimeout(async () => {
 32→    if (activeContextCount === 0 && browser !== null) {
 33→      const instance = browser;
 34→      browser = null;
 35→      totalContextCount = 0;
 36→      await instance.close();
 37→    }
 38→  }, BROWSER_IDLE_SHUTDOWN_MS);
 39→}
 40→
 41→async function ensureBrowser(): Promise<Browser> {
 42→  if (browser !== null) {
 43→    return browser;
 44→  }
 45→
 46→  const instance = await chromium.launch({ headless: true });
 47→
 48→  instance.on("disconnected", () => {
 49→    if (browser === instance) {
 50→      browser = null;
 51→      totalContextCount = 0;
 52→    }
 53→  });
 54→
 55→  browser = instance;
 56→  return instance;
 57→}
 58→
 59→async function createContext(): Promise<BrowserContext> {
 60→  if (
 61→    totalContextCount >= MAX_CONTEXTS_PER_BROWSER &&
 62→    activeContextCount <= 1 &&
 63→    browser !== null
 64→  ) {
 65→    const old = browser;
 66→    browser = null;
 67→    totalContextCount = 0;
 68→    await old.close();
 69→  }
 70→
 71→  const instance = await ensureBrowser();
 72→  activeContextCount++;
 73→  totalContextCount++;
 74→  clearIdleTimer();
 75→
 76→  return instance.newContext();
 77→}
 78→
 79→export async function acquireContext(): Promise<BrowserContext> {
 80→  if (activeContextCount >= MAX_CONCURRENT_BROWSER_CONTEXTS) {
 81→    return new Promise<BrowserContext>((resolve, reject) => {
 82→      queue.push({ resolve, reject });
 83→    });
 84→  }
 85→
 86→  return createContext();
 87→}
 88→
 89→export async function releaseContext(context: BrowserContext): Promise<void> {
 90→  await context.close();
 91→  activeContextCount--;
 92→
 93→  if (queue.length > 0) {
 94→    const next = queue.shift()!;
 95→    try {
 96→      const ctx = await createContext();
 97→      next.resolve(ctx);
 98→    } catch (err) {
 99→      next.reject(err instanceof Error ? err : new Error(String(err)));
100→    }
101→  } else if (activeContextCount === 0) {
102→    scheduleIdleShutdown();
103→  }
104→}
105→
106→export async function shutdownPool(): Promise<void> {
107→  clearIdleTimer();
108→
109→  while (queue.length > 0) {
110→    const entry = queue.shift()!;
111→    entry.reject(new Error("Pool shut down"));
112→  }
113→
114→  if (browser !== null) {
115→    const instance = browser;
116→    browser = null;
117→    await instance.close();
118→  }
119→
120→  activeContextCount = 0;
121→  totalContextCount = 0;
122→}
123→
124→export function getPoolStats() {
125→  return {
126→    activeContexts: activeContextCount,
127→    queueLength: queue.length,
128→    browserConnected: browser !== null,
129→    totalContextsServed: totalContextCount,
130→  };
131→}
