259→                targetFormat: latestDetail.session.targetFormat,
260→                selector,
261→                effect: {
262→                  type: "custom_style" as const,
263→                  ...effect,
264→                  description,
265→                },
266→                instruction: description,
267→                sourceSessionId: input.sessionId,
268→              });
269→              return { ruleId: rule.id };
270→            },
271→            onUpdateRule: async ({ ruleId, effect, description }) => {
272→              updateFormatRuleEffect(
273→                ruleId,
274→                { type: "custom_style" as const, ...effect, description },
275→                description,
276→              );
277→            },
278→            onDeleteRule: async (ruleId) => {
279→              disableFormatRule(ruleId, latestDetail.session.importId);
280→            },
281→          },
282→        });
283→
284→        // Phase 3 — persist assistant message + events
285→        withTransaction(() => {
286→          appendAdjustmentMessage(
287→            input.sessionId,
288→            "assistant",
289→            result.assistantMessage,
290→          );
291→
292→          for (const action of result.actions) {
293→            recordAdjustmentEvent({
294→              importId: latestDetail.session.importId,
295→              ruleId: action.ruleId,
296→              sessionId: input.sessionId,
297→              targetFormat: latestDetail.session.targetFormat,
298→              type:
299→                action.type === "deleted" ? "rule_disabled" : "rule_applied",
300→            });
301→          }
302→
303→          if (result.actions.length > 0) {
304→            markSessionApplied(input.sessionId);
305→          } else {
306→            recordAdjustmentEvent({
307→              importId: latestDetail.session.importId,
308→              sessionId: input.sessionId,
309→              targetFormat: latestDetail.session.targetFormat,
310→              type: "clarification_requested",
311→            });
312→          }
313→        });
314→      } catch (error) {
315→        if (error instanceof AgentUnavailableError) {
316→          throw new ORPCError("SERVICE_UNAVAILABLE", {
317→            message: error.message,
318→          });
319→        }
320→        if (error instanceof DOMException && error.name === "TimeoutError") {
321→          throw new ORPCError("GATEWAY_TIMEOUT", {
322→            message: "Die KI hat zu lange gebraucht. Bitte versuche es erneut.",
323→          });
324→        }
325→        throw new ORPCError("BAD_REQUEST", {
326→          message:
327→            error instanceof Error
328→              ? error.message
329→              : "Die Live-KI-Nachricht konnte nicht verarbeitet werden.",

