598→export function promoteRuleToProfile(ruleId: string) {
599→  const existingRule = getFormatRule(ruleId);
600→
601→  if (!existingRule) {
602→    throw new Error("Formatregel nicht gefunden.");
603→  }
604→
605→  if (existingRule.scope === "format_profile") {
606→    throw new Error("Regel ist bereits eine Profil-Regel.");
607→  }
608→
609→  const originalImportId = existingRule.importId;
610→  const timestamp = now();
611→
612→  db.transaction((tx) => {
613→    tx.update(formatRules)
614→      .set({
615→        scope: "format_profile",
616→        importId: null,
617→        updatedAt: timestamp,
618→      })
619→      .where(eq(formatRules.id, ruleId))
620→      .run();
621→
622→    if (!originalImportId) {
623→      throw new Error(
624→        "Regel hat keine gültige importId – Promote nicht möglich.",
625→      );
626→    }
627→
628→    recordAdjustmentEvent(
629→      {
630→        importId: originalImportId,
631→        ruleId: existingRule.id,
632→        sessionId: existingRule.sourceSessionId,
633→        targetFormat: existingRule.targetFormat,
634→        type: "rule_promoted",
635→      },
636→      tx,
637→    );
638→  });
