682→export function disableFormatRule(ruleId: string, importId?: string) {
683→  const existingRule = getFormatRule(ruleId);
684→
685→  if (!existingRule) {
686→    throw new Error("Formatregel nicht gefunden.");
687→  }
688→
689→  if (existingRule.status !== "active") {
