export function findReusableAdjustmentSession(
  input: CreateAdjustmentSessionInput,
) {
  return listAdjustmentSessions(input.importId, input.targetFormat).find(
    (session) =>
      session.status === "open" &&
      selectionsMatch(session.selection, input.selection),
  );
}
```

The function only matches sessions with `status === "open"` (line 231). However, the codebase shows that sessions can have an "applied" status (see `markSessionApplied` at line 426-431). 

When a user reopens the same selection in a new popover after a session has been applied, `findReusableAdjustmentSession` won't find the existing "applied" session, causing a duplicate session to be created. The function should also consider "applied" sessions for reuse since they represent completed work on the same selection.

