174→function buildSelectorSchema() {
175→  return {
176→    type: "object",
177→    properties: {
178→      strategy: {
179→        type: "string",
180→        enum: ["exact", "block_type", "prefix_before_colon", "markdown_table"],
181→        description:
182→          "exact = nur dieser eine Block, block_type = alle Blöcke dieses Typs.",
183→      },
184→      messageId: {
185→        type: "string",
186→        description: "ID der Nachricht (aus dem Kontext übernehmen).",
187→      },
188→      blockIndex: {
189→        type: "number",
190→        description: "Index des Blocks (aus dem Kontext übernehmen).",
191→      },
192→      blockType: {
193→        type: "string",
194→        enum: ["paragraph", "heading", "list", "quote", "code", "table"],
195→        description: "Typ des Blocks (aus dem Kontext übernehmen).",
196→      },
197→      lineStart: {
198→        type: "number",
199→        description: "Nur für Markdown: erste Zeile.",
200→      },
201→      lineEnd: {
202→        type: "number",
203→        description: "Nur für Markdown: letzte Zeile.",
204→      },
205→    },
206→    required: ["strategy"],
207→  };
208→}
209→
210→function buildEffectSchema() {
211→  return {
212→    type: "object",
213→    properties: {
214→      type: {
215→        type: "string",
216→        enum: ["custom_style"],
217→        description: "Immer 'custom_style'.",
218→      },
219→      containerStyle: {
220→        type: "object",
221→        description:
222→          "CSS für den äußeren Block-Wrapper (camelCase). Beispiele: { paddingLeft: '2rem', marginBottom: '1rem', backgroundColor: 'hsl(var(--accent))' }.",
223→      },
224→      textStyle: {
225→        type: "object",
226→        description:
227→          "CSS für den Text (camelCase). Beispiele: { fontSize: '1.25rem', fontWeight: '600', color: 'hsl(var(--primary))' }.",
228→      },
229→      itemStyle: {
230→        type: "object",
231→        description:
232→          "CSS für Kind-Elemente wie <li>, <td> (camelCase). Beispiele: { paddingLeft: '1rem', marginBottom: '0.5rem' }.",
233→      },
234→      textTransform: {
235→        type: "string",
236→        enum: ["bold_prefix_before_colon", "render_markdown_strong"],
237→      },
238→      markdownTransform: {
239→        type: "string",
240→        enum: [
241→          "promote_to_heading",
242→          "normalize_list_structure",
243→          "normalize_markdown_table",
244→          "reshape_markdown_block",
245→          "bold_prefix_before_colon",
246→        ],
247→      },
248→      headingLevel: {
249→        type: "number",
250→        description: "Überschriften-Ebene 1-6.",
251→      },
252→      insertBefore: { type: "string", enum: ["hr", "spacer"] },
253→      insertAfter: { type: "string", enum: ["hr", "spacer"] },
254→    },
255→    required: ["type"],
256→  };
257→}
258→
259→function buildTools() {
260→  return [
261→    {
262→      type: "function",
263→      name: "create_rule",
264→      description:
265→        "Erstellt eine neue Darstellungsregel für den ausgewählten Block.",
266→      parameters: {
267→        type: "object",
268→        properties: {
