322→
323→// ---------------------------------------------------------------------------
324→// Context Builder
325→// ---------------------------------------------------------------------------
326→
327→function blockToPlainText(block: Block) {
328→  switch (block.type) {
329→    case "paragraph":
330→    case "heading":
331→    case "quote":
332→    case "code":
333→      return block.text;
334→    case "list":
335→      return block.items.join("\n");
336→    case "table":
337→      return [
338→        block.headers.join(" | "),
339→        ...block.rows.map((row) => row.join(" | ")),
340→      ].join("\n");
341→  }
342→}
343→
344→function summarizeSelection(
345→  sessionDetail: AdjustmentSessionDetail,
346→  job: ImportJob | undefined,
347→) {
348→  const { selection, targetFormat } = sessionDetail.session;
349→
350→  if (targetFormat === "markdown") {
351→    const markdown = job?.artifacts?.markdown ?? "";
352→    const lines = markdown.split("\n");
353→    const lineStart = selection.lineStart ?? 1;
354→    const lineEnd = selection.lineEnd ?? lineStart;
355→
356→    return {
357→      currentExcerpt:
358→        lines.slice(lineStart - 1, lineEnd).join("\n") ||
359→        selection.selectedText,
360→      description: `Markdown-Zeilen ${lineStart}-${lineEnd}`,
361→      surrounding: {
362→        next: lines[lineEnd] ?? null,
363→        previous: lineStart > 1 ? (lines[lineStart - 2] ?? null) : null,
364→      },
365→    };
366→  }
367→
368→  const message = job?.conversation?.messages.find(
369→    (entry) => entry.id === selection.messageId,
370→  );
371→  const currentBlock = message?.blocks[selection.blockIndex];
372→  const previousBlock =
373→    selection.blockIndex > 0
374→      ? message?.blocks[selection.blockIndex - 1]
375→      : undefined;
376→  const nextBlock = message?.blocks[selection.blockIndex + 1];
377→
378→  return {
379→    currentExcerpt: currentBlock
380→      ? blockToPlainText(currentBlock)
381→      : selection.selectedText,
382→    description: `${selection.messageRole} message ${selection.messageIndex + 1}, ${selection.blockType}`,
383→    surrounding: {
384→      next: nextBlock ? blockToPlainText(nextBlock) : null,
385→      previous: previousBlock ? blockToPlainText(previousBlock) : null,
386→    },
387→  };
388→}
389→
390→function buildSelectionContext(input: RunAgentTurnInput) {
391→  const { activeRules, job, sessionDetail } = input;
392→  const { selection, targetFormat } = sessionDetail.session;
393→  const selectionContext = summarizeSelection(sessionDetail, job);
394→  const lines: string[] = [];
395→
396→  lines.push("## Ausgewählter Block");
397→  lines.push(`Format: ${targetFormat}`);
398→  lines.push(
399→    `Block: ${selection.blockType} (messageId: "${selection.messageId}", blockIndex: ${selection.blockIndex})`,
400→  );
401→  lines.push(
402→    `Rolle: ${selection.messageRole}, Nachricht ${selection.messageIndex + 1}`,
403→  );
404→  if (selection.lineStart != null) {
405→    lines.push(
406→      `Zeilen: ${selection.lineStart}-${selection.lineEnd ?? selection.lineStart}`,
407→    );
408→  }
409→  lines.push("");
410→  lines.push("Inhalt des ausgewählten Blocks:");
411→  lines.push("```");
412→  lines.push(selectionContext.currentExcerpt);
413→  lines.push("```");
414→
415→  if (selectionContext.surrounding.previous) {
416→    lines.push("");
417→    lines.push("Block davor:");
418→    lines.push(`> ${selectionContext.surrounding.previous.slice(0, 200)}`);
419→  }
420→  if (selectionContext.surrounding.next) {
421→    lines.push("");
422→    lines.push("Block danach:");
423→    lines.push(`> ${selectionContext.surrounding.next.slice(0, 200)}`);
424→  }
425→
426→  const active = activeRules
427→    .filter((rule) => rule.status === "active")
428→    .slice(0, 8);
429→  if (active.length > 0) {
430→    lines.push("");
431→    lines.push("## Bereits aktive Regeln");
432→    for (const rule of active) {
433→      const selectorStr = rule.selector
434→        ? JSON.stringify(rule.selector)
435→        : "(kein Selektor)";
436→      lines.push(
437→        `- [${rule.id}] ${rule.instruction ?? "(keine Beschreibung)"} — Selektor: ${selectorStr}`,
438→      );
439→    }
440→  }
441→
442→  return lines.join("\n");
443→}
444→
445→type InputMessage = {
446→  content: Array<{ text: string; type: "input_text" }>;
447→  role: "system" | "user" | "assistant";
448→};
449→
450→function buildInputMessages(input: RunAgentTurnInput): InputMessage[] {
451→  const targetFormat = input.sessionDetail.session.targetFormat;
452→  const messages: InputMessage[] = [
453→    {
454→      content: [{ text: buildSystemPrompt(targetFormat), type: "input_text" }],
455→      role: "system",
456→    },
457→    {
458→      content: [{ text: buildSelectionContext(input), type: "input_text" }],
459→      role: "user",
460→    },
461→  ];
462→
463→  // Add session messages as real multi-turn conversation so the model
464→  // understands the full dialog history and can reference prior turns.
465→  for (const msg of input.sessionDetail.messages) {
466→    messages.push({
467→      content: [{ text: msg.content, type: "input_text" }],
468→      role: msg.role === "user" ? "user" : "assistant",
469→    });
470→  }
471→
472→  return messages;
473→}
474→
475→// ---------------------------------------------------------------------------
476→// OpenAI helpers
477→// ---------------------------------------------------------------------------
478→
479→function isRecord(value: unknown): value is Record<string, unknown> {
480→  return Boolean(value) && typeof value === "object" && !Array.isArray(value);
481→}
482→
483→function extractFunctionCalls(payload: ResponsesPayload): FunctionCallItem[] {
484→  if (!Array.isArray(payload.output)) {
485→    return [];
486→  }
487→
488→  return payload.output.flatMap((item) => {
489→    if (!isRecord(item) || item.type !== "function_call") {
490→      return [];
491→    }
492→
493→    const callId = typeof item.call_id === "string" ? item.call_id : null;
494→    const name = typeof item.name === "string" ? item.name : null;
495→    const args = typeof item.arguments === "string" ? item.arguments : null;
496→
497→    if (!callId || !name || !args) {
498→      return [];
499→    }
500→
501→    return [{ arguments: args, callId, name }];
502→  });
503→}
504→
505→function extractAssistantMessage(payload: ResponsesPayload) {
506→  if (typeof payload.output_text === "string" && payload.output_text.trim()) {
507→    return payload.output_text.trim();
508→  }
509→
510→  if (!Array.isArray(payload.output)) {
511→    return "";
512→  }
513→
514→  return payload.output
515→    .flatMap((item) => {
516→      if (
517→        !isRecord(item) ||
518→        item.type !== "message" ||
519→        item.role !== "assistant"
520→      ) {
521→        return [];
522→      }
523→
524→      const content = item.content;
525→      if (!Array.isArray(content)) {
526→        return [];
527→      }
528→
529→      return content.flatMap((entry) => {
530→        if (!isRecord(entry) || entry.type !== "output_text") {
531→          return [];
532→        }
533→
534→        return typeof entry.text === "string" && entry.text.trim()
535→          ? [entry.text.trim()]
536→          : [];
537→      });
538→    })
539→    .join("\n")
540→    .trim();
541→}
542→
543→async function requestOpenAiResponse(
544→  body: Record<string, unknown>,
545→  config: ReturnType<typeof readAdjustmentAiConfig>,
546→) {
547→  const response = await fetch(`${config.openai?.apiBaseUrl}/responses`, {
548→    method: "POST",
549→    headers: {
550→      "Content-Type": "application/json",
551→      Authorization: `Bearer ${config.openai?.apiKey}`,
552→    },
553→    body: JSON.stringify({
554→      model: config.model,
555→      reasoning: { effort: "low" },
556→      store: true,
557→      ...body,
558→    }),
559→    signal: AbortSignal.timeout(config.timeoutMs),
560→  });
561→
562→  if (!response.ok) {
563→    const errorText = await response.text();
564→    throw new AgentUnavailableError(
565→      `Die Live-KI-Antwort war nicht verfügbar (${response.status}). ${errorText.slice(0, 240)}`,
566→    );
567→  }
568→
569→  return (await response.json()) as ResponsesPayload;
570→}
571→
572→// ---------------------------------------------------------------------------
573→// Tool execution with validation
574→// ---------------------------------------------------------------------------
575→
576→function validateEffect(effect: unknown): {
577→  ok: boolean;
578→  data?: Record<string, unknown>;
579→  error?: string;
580→} {
581→  const result = customStyleEffectSchema.safeParse(effect);
582→  if (result.success) {
583→    return { ok: true, data: result.data as Record<string, unknown> };
584→  }
585→
586→  const issues = result.error.issues
587→    .map((i) => `${i.path.join(".")}: ${i.message}`)
588→    .join("; ");
589→  return { ok: false, error: `Effect-Validierung fehlgeschlagen: ${issues}` };
590→}
591→
592→async function executeToolCall(
593→  call: FunctionCallItem,
594→  callbacks: RunAgentTurnInput["callbacks"],
595→  actions: ActionRecord[],
596→): Promise<string> {
597→  const args = JSON.parse(call.arguments) as Record<string, unknown>;
598→
599→  if (call.name === "create_rule") {
600→    const effectValidation = validateEffect(args.effect);
601→    if (!effectValidation.ok) {
602→      return JSON.stringify({ ok: false, error: effectValidation.error });
603→    }
604→
605→    try {
606→      const { ruleId } = await callbacks.onCreateRule({
607→        selector: args.selector as Record<string, unknown>,
608→        effect: effectValidation.data as Record<string, unknown>,
609→        description: String(args.description ?? ""),
610→      });
611→      actions.push({ type: "created", ruleId });
612→      return JSON.stringify({ ok: true, ruleId });
613→    } catch (error) {
614→      return JSON.stringify({
615→        ok: false,
616→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
617→      });
618→    }
619→  }
620→
621→  if (call.name === "update_rule") {
622→    const effectValidation = validateEffect(args.effect);
623→    if (!effectValidation.ok) {
624→      return JSON.stringify({ ok: false, error: effectValidation.error });
625→    }
626→
627→    const ruleId = String(args.ruleId ?? "");
628→
629→    try {
630→      await callbacks.onUpdateRule({
631→        ruleId,
632→        effect: effectValidation.data as Record<string, unknown>,
633→        description:
634→          typeof args.description === "string" ? args.description : undefined,
635→      });
636→      actions.push({ type: "updated", ruleId });
637→      return JSON.stringify({ ok: true, ruleId });
638→    } catch (error) {
639→      return JSON.stringify({
640→        ok: false,
641→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
642→      });
643→    }
644→  }
645→
646→  if (call.name === "delete_rule") {
647→    const ruleId = String(args.ruleId ?? "");
648→
649→    try {
650→      await callbacks.onDeleteRule(ruleId);
651→      actions.push({ type: "deleted", ruleId });
652→      return JSON.stringify({ ok: true, ruleId });
653→    } catch (error) {
654→      return JSON.stringify({
655→        ok: false,
656→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
657→      });
658→    }
659→  }
660→
661→  return JSON.stringify({
662→    ok: false,
663→    error: `Unbekannter Tool-Call: ${call.name}`,
664→  });
665→}
666→
667→// ---------------------------------------------------------------------------
668→// Main agent turn
669→// ---------------------------------------------------------------------------
670→
671→export async function runAgentTurn(input: RunAgentTurnInput): Promise<{
672→  assistantMessage: string;
673→  actions: ActionRecord[];
674→}> {
675→  const config = readAdjustmentAiConfig();
676→
677→  if (!config.enabled || config.provider !== "openai" || !config.openai) {
678→    throw new AgentUnavailableError(
679→      "Live-KI-Anpassungen sind aktuell nicht konfiguriert. Hinterlege einen OpenAI-Zugang, bevor du diesen Chat nutzt.",
680→    );
681→  }
682→
683→  const actions: ActionRecord[] = [];
684→
685→  const inputMessages = buildInputMessages(input);
686→
687→  let payload = await requestOpenAiResponse(
688→    {
689→      input: inputMessages,
690→      tool_choice: "auto",
691→      tools: buildTools(),
692→    },
693→    config,
694→  );
695→
696→  for (let round = 0; round < MAX_TOOL_ROUNDS; round += 1) {
697→    const functionCalls = extractFunctionCalls(payload);
698→    if (functionCalls.length === 0) {
699→      break;
700→    }
701→
702→    if (!payload.id) {
703→      throw new Error(
704→        "Die KI-Antwort enthält keine Response-ID für den Tool-Loop.",
705→      );
706→    }
707→
708→    const toolOutputs = [];
709→
710→    for (const call of functionCalls) {
711→      const result = await executeToolCall(call, input.callbacks, actions);
712→      toolOutputs.push({
713→        type: "function_call_output",
714→        call_id: call.callId,
715→        output: result,
716→      });
717→    }
718→
719→    payload = await requestOpenAiResponse(
720→      {
721→        input: toolOutputs,
722→        previous_response_id: payload.id,
723→        tool_choice: "auto",
724→        tools: buildTools(),
725→      },
726→      config,
727→    );
728→  }
729→
730→  const rawMessage = extractAssistantMessage(payload);
731→  let assistantMessage: string;
732→
733→  if (rawMessage) {
734→    assistantMessage = rawMessage;
735→  } else if (actions.length > 0) {
736→    assistantMessage = "Die Änderung ist jetzt sichtbar.";
737→  } else {
738→    // The AI returned no text and took no actions — retry once with an
739→    // explicit nudge so the user sees an actual question instead of a
740→    // generic placeholder.
741→    const retryPayload = await requestOpenAiResponse(
742→      {
743→        input: [
744→          ...inputMessages,
745→          {
746→            content: [
747→              {
748→                text: "Du hast gerade keine Antwort gegeben. Bitte stelle dem Nutzer jetzt eine konkrete Rückfrage, damit du eine passende Regel erstellen kannst.",
749→                type: "input_text",
750→              },
751→            ],
752→            role: "user",
753→          },
754→        ],
755→        tool_choice: "none",
756→        tools: buildTools(),
757→      },
758→      config,
759→    );
760→
761→    assistantMessage =
762→      extractAssistantMessage(retryPayload) ||
763→      "Ich konnte die Anfrage nicht verstehen. Kannst du bitte genauer beschreiben, was du ändern möchtest?";
764→  }
765→
766→  return { assistantMessage, actions };
767→}
