type UndoToastProps = {
  message: string;
  onUndo: () => void;
  onDismiss: () => void;
  duration?: number;
};

export function UndoToast({
  message,
  onUndo,
  onDismiss,
  duration = 8000,
}: UndoToastProps) {
  const [visible, setVisible] = useState(true);

  useEffect(() => {
    const timer = setTimeout(() => {
      setVisible(false);
      onDismiss();
    }, duration);

